cat > /tmp/aa55udp_float32_repro.go <<'EOF'
package main

import (
    "context"
    "encoding/binary"
    "fmt"
    "math"
    "net"
    "os"
    "strings"
    "time"

    "github.com/evcc-io/evcc/plugin"
)

func main() {
    expectFixed := os.Getenv("EXPECT_FIXED") == "1"

    var done func()
    var responses chan []byte
    if expectFixed {
        var err error
        responses, done, err = startServer()
        if err != nil {
            fmt.Fprintf(os.Stderr, "server setup failed: %v\n", err)
            os.Exit(1)
        }
        defer done()
    }

    p, err := plugin.NewAA55UDPFromConfig(context.Background(), map[string]interface{}{
        "host":     "127.0.0.1",
        "register": 36017,
        "count":    2,
        "decode":   "float32",
        "scale":    0.001,
    })

    if !expectFixed {
        if err != nil && strings.Contains(err.Error(), `unsupported decode "float32"`) {
            fmt.Println("reproduced unsupported float32 decode during aa55udp construction")
            return
        }
        if err != nil {
            fmt.Fprintf(os.Stderr, "expected unsupported float32 decode, got different error: %v\n", err)
        } else {
            fmt.Fprintln(os.Stderr, "expected unsupported float32 decode, got success")
        }
        os.Exit(1)
    }

    if err != nil {
        fmt.Fprintf(os.Stderr, "expected float32 config support, got error: %v\n", err)
        os.Exit(1)
    }

    getter, err := p.FloatGetter()
    if err != nil {
        fmt.Fprintf(os.Stderr, "FloatGetter failed: %v\n", err)
        os.Exit(1)
    }

    responses <- aa55Float32Response(12345.5)
    got, err := getter()
    if err != nil {
        fmt.Fprintf(os.Stderr, "float32 query failed: %v\n", err)
        os.Exit(1)
    }
    want := 12.3455
    if math.Abs(got-want) > 0.00001 {
        fmt.Fprintf(os.Stderr, "decoded scaled value mismatch: got %.8f want %.8f\n", got, want)
        os.Exit(1)
    }

    responses <- []byte{0xAA, 0x55, 0xF7, 0x03, 0x02, 0x12, 0x34, 0x00, 0x00}
    _, err = getter()
    if err == nil || !strings.Contains(err.Error(), "payload too short for float32") {
        fmt.Fprintf(os.Stderr, "expected short-payload float32 error, got: %v\n", err)
        os.Exit(1)
    }

    fmt.Println("float32 aa55udp construction, decode, scaling, and short-payload edge case verified")
}

func startServer() (chan []byte, func(), error) {
    pc, err := net.ListenPacket("udp4", "127.0.0.1:8899")
    if err != nil {
        return nil, nil, err
    }

    responses := make(chan []byte, 2)
    stop := make(chan struct{})

    go func() {
        buf := make([]byte, 512)
        for {
            _ = pc.SetReadDeadline(time.Now().Add(100 * time.Millisecond))
            _, addr, err := pc.ReadFrom(buf)
            if err != nil {
                select {
                case <-stop:
                    return
                default:
                    continue
                }
            }
            response := <-responses
            _, _ = pc.WriteTo(response, addr)
        }
    }()

    return responses, func() { close(stop); _ = pc.Close() }, nil
}

func aa55Float32Response(v float32) []byte {
    payload := make([]byte, 4)
    binary.BigEndian.PutUint32(payload, math.Float32bits(v))
    frame := []byte{0xAA, 0x55, 0xF7, 0x03, byte(len(payload))}
    frame = append(frame, payload...)
    frame = append(frame, 0x00, 0x00)
    return frame
}
EOF
