func startServer() (chan []byte, func(), error) {
    pc, err := net.ListenPacket("udp4", "127.0.0.1:8899")
    if err != nil {
        return nil, nil, err
    }

    responses := make(chan []byte, 2)
    stop := make(chan struct{})

    go func() {
        buf := make([]byte, 512)
        for {
            _ = pc.SetReadDeadline(time.Now().Add(100 * time.Millisecond))
            _, addr, err := pc.ReadFrom(buf)
            if err != nil {
                select {
                case <-stop:
                    return
                default:
                    continue
                }
            }
            response := <-responses
            _, _ = pc.WriteTo(response, addr)
        }
    }()

    return responses, func() { close(stop); _ = pc.Close() }, nil
}

func aa55Float32Response(v float32) []byte {
    payload := make([]byte, 4)
    binary.BigEndian.PutUint32(payload, math.Float32bits(v))
    frame := []byte{0xAA, 0x55, 0xF7, 0x03, byte(len(payload))}
    frame = append(frame, payload...)
    frame = append(frame, 0x00, 0x00)
    return frame
}
